15→		`INSERT INTO content_drafts (session_id, ai_draft, content_type) VALUES (?, ?, ?)`,
16→		sessionID, aiDraft, contentType,
17→	)
18→	if err != nil {
19→		return 0, fmt.Errorf("saving draft: %w", err)
20→	}
21→	return res.LastInsertId()
